import java.util.concurrent.*;
import java.time.*;

public class VirtualThreadsDemo {

    // Simulated I/O-bound task (sleep = blocking like a DB query)
    static Runnable ioTask(int id) {
        return () -> {
            try {
                Thread.sleep(100); // 100ms blocking I/O
                // System.out.println("Task " + id + " done on: " + Thread.currentThread());
            } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
        };
    }

    public static void main(String[] args) throws Exception {
        int taskCount = 10_000;

        // ── Platform threads (100-thread pool) ────────────────────
        Instant t1 = Instant.now();
        try (var pool = Executors.newFixedThreadPool(100)) {
            var futures = new java.util.ArrayList<Future<?>>();
            for (int i = 0; i < taskCount; i++)
                futures.add(pool.submit(ioTask(i)));
            for (var f : futures) f.get();
        }
        System.out.println("Platform threads: " + Duration.between(t1, Instant.now()).toMillis() + "ms");
        // ~10 seconds (10,000 tasks / 100 threads × 100ms each)

        // ── Virtual threads (one per task) ────────────────────────
        Instant t2 = Instant.now();
        try (var vpool = Executors.newVirtualThreadPerTaskExecutor()) {
            var futures = new java.util.ArrayList<Future<?>>();
            for (int i = 0; i < taskCount; i++)
                futures.add(vpool.submit(ioTask(i)));
            for (var f : futures) f.get();
        }
        System.out.println("Virtual threads:   " + Duration.between(t2, Instant.now()).toMillis() + "ms");
        // ~100ms (all 10,000 run in parallel on carrier threads)

        // ── Direct creation ───────────────────────────────────────
        Thread vt = Thread.ofVirtual().name("my-vthread").start(() -> {
            System.out.println("Running on: " + Thread.currentThread());
            System.out.println("Is virtual: " + Thread.currentThread().isVirtual());
        });
        vt.join();
    }
}

