import java.util.concurrent.*;
import java.util.concurrent.locks.*;
import java.util.*;

public class Q2 {
    public static void main(String[] args) throws Exception {
        final int TASKS = 100, ITERS = 1000;

        // Part 1: synchronized
        long[] count1 = {0};
        Object lock1 = new Object();
        List<Future<?>> f1 = new ArrayList<>();
        try (var e = Executors.newVirtualThreadPerTaskExecutor()) {
            for (int t = 0; t < TASKS; t++)
                f1.add(e.submit(() -> { for (int i = 0; i < ITERS; i++) synchronized(lock1) { count1[0]++; } return null; }));
            for (var f : f1) f.get();
        }
        System.out.println(count1[0]);

        // Part 2: ReentrantLock
        long[] count2 = {0};
        ReentrantLock lock2 = new ReentrantLock();
        List<Future<?>> f2 = new ArrayList<>();
        try (var e = Executors.newVirtualThreadPerTaskExecutor()) {
            for (int t = 0; t < TASKS; t++)
                f2.add(e.submit(() -> {
                    for (int i = 0; i < ITERS; i++) {
                        lock2.lock();
                        try { count2[0]++; } finally { lock2.unlock(); }
                    }
                    return null;
                }));
            for (var f : f2) f.get();
        }
        System.out.println(count2[0]);
    }
}

