import java.util.concurrent.*;
import java.util.*;

public class Q3 {
    public static void main(String[] args) throws Exception {
        ThreadFactory factory = Thread.ofVirtual().name("worker-", 1).factory();
        List<Future<?>> futures = new ArrayList<>();
        try (var exec = Executors.newThreadPerTaskExecutor(factory)) {
            for (int i = 0; i < 5; i++) {
                futures.add(exec.submit(() -> {
                    System.out.println(Thread.currentThread().getName() + ": virtual=" + Thread.currentThread().isVirtual());
                    return null;
                }));
            }
            for (var f : futures) f.get();
        }
    }
}
